function Get-ParsecIngredientOperations {
    return @{ capture = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) Get-ParsecServiceCaptureResult -Arguments $Arguments }; apply = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) Start-Service -Name $Arguments.service_name; New-ParsecResult -Status 'Succeeded' -Message "Started service '$($Arguments.service_name)'." }; verify = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $service = Get-Service -Name $Arguments.service_name -ErrorAction Stop; if ($service.Status -eq 'Running') { return New-ParsecResult -Status 'Succeeded' -Message 'Service is running.' -Observed @{ service_name = $service.Name; status = [string] $service.Status } }; New-ParsecResult -Status 'Failed' -Message "Service '$($Arguments.service_name)' is not running." -Observed @{ service_name = $service.Name; status = [string] $service.Status } }; reset = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) Stop-Service -Name $Arguments.service_name; New-ParsecResult -Status 'Succeeded' -Message "Stopped service '$($Arguments.service_name)'." } }
}
